class Allocator {
    private int[] mem;

    public Allocator(int n) {
        mem = new int[n];
    }

    public int allocate(int size, int mID) {
        int start = -1, count = 0;
        for (int i = 0; i <= mem.length; i++) {
            if (i < mem.length && mem[i] == 0) {
                if (start == -1) start = i;
                count++;
            } else {
                if (count >= size) {
                    for (int j = start; j < start + size; j++) {
                        mem[j] = mID;
                    }
                    return start;
                }
                start = -1;
                count = 0;
            }
        }
        return -1;
    }

    public int free(int mID) {
        int count = 0;
        for (int i = 0; i < mem.length; i++) {
            if (mem[i] == mID) {
                count++;
                mem[i] = 0;
            }
        }
        return count;
    }
}
